import { Component } from '@angular/core';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [FormsModule],
  template: `
    <main class="app">
      <section class="card">
        <h1>Dynamic Table</h1>
        <p class="hint">Enter rows & columns, then generate a table grid.</p>

        <div class="controls">
          <label>
            <span>Rows</span>
            <input type="number" min="0" [(ngModel)]="rowInput" />
          </label>
          <label>
            <span>Columns</span>
            <input type="number" min="0" [(ngModel)]="colInput" />
          </label>
          <button (click)="updateTable()">Generate table</button>
        </div>

        @if (rows.length && cols.length) {
          <div class="preview">
            <table class="grid" aria-label="dynamic table">
              <tbody>
                @for (row of rows; track row; let rowIndex = $index) {
                  <tr>
                    @for (column of cols; track column; let colIndex = $index) {
                      <td>
                        R{{ rowIndex + 1 }}C{{ colIndex + 1 }}
                      </td>
                    }
                  </tr>
                }
              </tbody>
            </table>
          </div>
        } @else {
          <p class="empty">Set rows & columns, then generate the table.</p>
        }
      </section>
    </main>
  `,
  styles: [
    `.app{min-height:100vh;display:grid;place-items:center;background:#020617;color:#e5e7eb;padding:24px;}`,
    `.card{width:100%;max-width:640px;padding:20px 24px;background:#020617;border-radius:16px;border:1px solid #1f2937;display:grid;gap:16px;}`,
    `h1{margin:0;font-size:20px;font-weight:700;}`,
    `.hint{margin:0;font-size:13px;color:#9ca3af;}`,
    `.controls{display:flex;flex-wrap:wrap;gap:12px;align-items:flex-end;}`,
    `label{display:flex;flex-direction:column;gap:4px;font-size:13px;}`,
    `input{background:#020617;border:1px solid #374151;border-radius:10px;padding:6px 10px;color:#e5e7eb;min-width:80px;}`,
    `button{background:#a3e635;color:#0b1020;border:none;border-radius:10px;padding:8px 14px;font-weight:600;cursor:pointer;}`,
    `button:hover{filter:brightness(1.05);}`,
    `.preview{overflow:auto;border-radius:12px;border:1px solid #1f2937;padding:12px;background:#020617;}`,
    `.grid{width:100%;border-collapse:collapse;}`,
    `td{border:1px solid #1f2937;padding:6px 10px;font-size:13px;text-align:center;}`,
    `.empty{margin:0;font-size:13px;color:#9ca3af;}`
  ]
})
export class AppComponent {
  rowInput = 3;
  colInput = 4;

  rows: number[] = [];
  cols: number[] = [];

  constructor() {
    this.updateTable();
  }

  private normalizeCount(raw: number): number {
    if (!Number.isFinite(raw)) return 0;
    const n = Math.floor(raw);
    const clamped = Math.max(0, Math.min(n, 20));
    return clamped;
  }

  updateTable(): void {
    const rows = this.normalizeCount(this.rowInput);
    const cols = this.normalizeCount(this.colInput);

    this.rows = Array.from({ length: rows }, (_, i) => i);
    this.cols = Array.from({ length: cols }, (_, i) => i);
  }
}
